import Foundation

class LocalizedNewsProvider {

    func getNewsUpdates(for demographics: [String], completion: @escaping ([NewsUpdate]?) -> Void) {
        // Load localized news updates from JSON file
        guard let path = Bundle.main.path(forResource: "NewsUpdates", withExtension: "json") else {
            completion(nil)
            return
        }

        do {
            let data = try Data(contentsOf: URL(fileURLWithPath: path))
            let newsUpdates = try JSONDecoder().decode([NewsUpdate].self, from: data)

            // Filter news updates based on demographics
            var filteredNewsUpdates: [NewsUpdate] = []
            for newsUpdate in newsUpdates {
                for demographic in demographics {
                    if newsUpdate.demographics.contains(demographic) {
                        filteredNewsUpdates.append(newsUpdate)
                        break
                    }
                }
            }

            completion(filteredNewsUpdates)
        } catch {
            print("Error loading news updates: \(error)")
            completion(nil)
        }
    }
}

struct NewsUpdate: Codable {
    let title: String
    let description: String
    let demographics: [String]
}
